import React, { useState, useEffect } from 'react';
import { useLocation, useNavigate } from 'react-router-dom';
import { loadStripe } from '@stripe/stripe-js';
import { Elements, CardElement, useStripe, useElements } from '@stripe/react-stripe-js';

// Initialize Stripe with YOUR publishable key
const stripePromise = loadStripe('pk_live_your_publishable_key_here'); // Replace with your actual key

// Stripe Checkout Form Component
const StripeCheckoutForm = ({ orderData, appliedCoupon, finalAmount }) => {
  const stripe = useStripe();
  const elements = useElements();
  const navigate = useNavigate();
  const [isProcessing, setIsProcessing] = useState(false);
  const [paymentError, setPaymentError] = useState('');

  const handleSubmit = async (event) => {
    event.preventDefault();
    
    if (!stripe || !elements) {
      return;
    }

    setIsProcessing(true);
    setPaymentError('');

    try {
      // Create payment intent on your backend (you'll need a small backend for this)
      const response = await fetch('/api/create-payment-intent', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({
          amount: finalAmount * 100, // Convert to pennies
          currency: 'gbp',
          description: `Ad Space #${orderData.squareNumber} - ${orderData.businessName}`,
        }),
      });

      const { clientSecret } = await response.json();

      // Confirm payment with Stripe
      const result = await stripe.confirmCardPayment(clientSecret, {
        payment_method: {
          card: elements.getElement(CardElement),
          billing_details: {
            name: orderData.businessName,
            email: orderData.contactEmail,
          },
        },
      });

      if (result.error) {
        setPaymentError(result.error.message);
        setIsProcessing(false);
      } else {
        // Payment successful!
        console.log('Payment successful:', result.paymentIntent);
        
        // Navigate to success page
        navigate('/success', {
          state: {
            ...orderData,
            orderId: `CLK-${result.paymentIntent.id}`,
            paymentDate: new Date().toISOString(),
            couponUsed: appliedCoupon,
            finalAmount: finalAmount,
            discountAmount: appliedCoupon ? (orderData.duration * appliedCoupon.discountPercent) / 100 : 0,
            isRealPayment: true
          }
        });
      }
    } catch (error) {
      console.error('Payment error:', error);
      setPaymentError('Payment failed. Please try again.');
      setIsProcessing(false);
    }
  };

  return (
    <form onSubmit={handleSubmit} className="payment-form">
      <div className="form-section">
        <h3>💳 Payment Details</h3>
        
        <div className="form-group">
          <label>Card Information</label>
          <div className="stripe-card-element">
            <CardElement
              options={{
                style: {
                  base: {
                    fontSize: '16px',
                    color: '#424770',
                    '::placeholder': {
                      color: '#aab7c4',
                    },
                  },
                },
              }}
            />
          </div>
        </div>

        {paymentError && (
          <div className="payment-error">
            ❌ {paymentError}
          </div>
        )}

        <button 
          type="submit" 
          disabled={!stripe || isProcessing || finalAmount === 0}
          className="btn-primary"
        >
          {isProcessing ? 'Processing...' : `Pay £${finalAmount}.00 Now`}
        </button>
      </div>
    </form>
  );
};

// Main Checkout Component
const Checkout = () => {
  const location = useLocation();
  const navigate = useNavigate();
  const orderData = location.state || {};
  
  const [couponCode, setCouponCode] = useState('');
  const [appliedCoupon, setAppliedCoupon] = useState(null);
  const [couponError, setCouponError] = useState('');

  // ... (keep your existing coupon logic from previous version)

  // Calculate totals (same as before)
  const baseAmount = orderData.duration || 0;
  const discountAmount = appliedCoupon 
    ? (baseAmount * appliedCoupon.discountPercent) / 100 
    : 0;
  const finalAmount = Math.max(0, baseAmount - discountAmount);

  // For free campaigns (100% discount)
  const handleFreeCampaign = () => {
    navigate('/success', {
      state: {
        ...orderData,
        orderId: `CLK-FREE-${Date.now()}`,
        paymentDate: new Date().toISOString(),
        couponUsed: appliedCoupon,
        finalAmount: 0,
        discountAmount: discountAmount,
        isRealPayment: false
      }
    });
  };

  return (
    <div className="checkout-container">
      <div className="checkout-header">
        <h1>💳 Complete Your Payment</h1>
        <p>Secure payment processed via Stripe</p>
      </div>

      <div className="checkout-content">
        {/* Order Summary (keep your existing order summary) */}
        <div className="order-summary">
          {/* ... your existing order summary code ... */}
        </div>

        {/* Coupon Section (keep your existing coupon section) */}
        <div className="coupon-section-integrated">
          {/* ... your existing coupon code ... */}
        </div>

        {/* Payment Section */}
        {finalAmount > 0 ? (
          <Elements stripe={stripePromise}>
            <StripeCheckoutForm 
              orderData={orderData}
              appliedCoupon={appliedCoupon}
              finalAmount={finalAmount}
            />
          </Elements>
        ) : (
          <div className="free-campaign-notice">
            <h4>🎉 Free Campaign Activated!</h4>
            <p>No payment required. Click below to start your free campaign.</p>
            <button onClick={handleFreeCampaign} className="btn-primary">
              Start Free 10-Day Campaign
            </button>
          </div>
        )}
      </div>
    </div>
  );
};

export default Checkout;
